const data = $json.body || $json;
const selected = data.selected_results || [];

if (!Array.isArray(selected) || selected.length === 0) {
  return {
    success: false,
    message: '선택된 링크가 없습니다.',
    received_body: data
  };
}

const urls = selected
  .map(item => item.url)
  .filter(url => typeof url === 'string' && url.trim() !== '');

if (urls.length === 0) {
  return {
    success: false,
    message: '유효한 URL이 없습니다.',
    selected_results: selected
  };
}

const limitedUrls = urls.slice(0, 10);
const limitedSelected = selected.filter(item => limitedUrls.includes(item.url));

// 리포트 유형별 기본값 처리
const reportType = data.report_type || 'trend_brief';
const audienceLevel = data.audience_level || 'division_head';
const reportDepth = data.report_depth || 'standard';
const actionOrientation = data.action_orientation !== undefined ? data.action_orientation : true;
const riskSensitivity = data.risk_sensitivity || 'normal';


// 회사 맥락 Google Docs 문서 URL/ID 처리
const rawDocInput = data.company_context_doc_url || data.company_context_doc_id || data.context_doc_url || data.context_doc_id || '';
let companyContextDocId = '';
let companyContextDocUrl = '';

if (rawDocInput) {
  const raw = String(rawDocInput).trim();
  const m = raw.match(/\/document\/d\/([^/]+)/);
  companyContextDocId = m ? m[1] : raw;
  companyContextDocUrl = raw.startsWith('http')
    ? raw
    : `https://docs.google.com/document/d/${companyContextDocId}/edit`;
}


return {
  success: true,
  keyword: data.keyword || '',
  insight_guide: data.insight_guide || '',
  analysis_viewpoint: data.analysis_viewpoint || 'business_expansion',
  report_type: reportType,
  audience_level: audienceLevel,
  report_depth: reportDepth,
  action_orientation: actionOrientation,
  risk_sensitivity: riskSensitivity,
  selected_count: limitedSelected.length,
  selected_results: limitedSelected,
  urls: limitedUrls,
  company_context_doc_id: companyContextDocId,
  company_context_doc_url: companyContextDocUrl,
  requested_at: new Date().toISOString()
};

// =============================================
// 5. Code - 도메인별 본문 정제 + 프롬프트 조립
// 목적: Tavily Extract 결과에서 메뉴/푸터/관련기사 노이즈를 줄이고,
//      주요 언론사/공식사이트별 룰 + 품질점수 + 핵심본문 압축을 적용한다.
