try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  parsed = raw;
}

const extractResults = parsed?.results || parsed?.content?.results || [];
const failedResults  = parsed?.failed_results || parsed?.content?.failed_results || [];

const prev = $('2. Code - 선택 URL 파싱').item.json;
