function getHost(url) {
  const s = String(url || '').trim();
  if (!s) return '';
  // n8n 환경에서 URL 객체가 간헐적으로 실패하는 경우를 피하기 위한 regex fallback
  const m = s.match(/^(?:https?:\/\/)?(?:www\.)?([^\/?#\s]+)/i);
  return m ? m[1].replace(/^www\./, '').toLowerCase() : '';
}

function getItemUrl(item = {}, matched = {}) {
  return String(
    item.url ||
    item.source_url ||
    item.raw_url ||
    item.link ||
    item.href ||
    item.metadata?.url ||
    item.meta?.url ||
    matched.url ||
    ''
  ).trim();
}

function normUrl(u) {
  return String(u || '').replace(/#.*$/, '').replace(/[?&]utm_[^=&]+=[^&]+/g, '').replace(/\/$/, '').trim();
}

function sameUrl(a, b) {
  return normUrl(a) && normUrl(a) === normUrl(b);
}

function hostMatches(host, domain) {
  return host === domain || host.endsWith('.' + domain);
