function getDomainRule(host) {
  return DOMAIN_RULES.find(rule => rule.domains.some(d => hostMatches(host, d))) || null;
}

function escapeRegExp(s) {
  return String(s || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function stripMarkdownAndHtml(text) {
  let t = String(text || '');
  t = t.replace(/\r/g, '\n');
  t = t.replace(/<script[\s\S]*?<\/script>/gi, '');
  t = t.replace(/<style[\s\S]*?<\/style>/gi, '');
  t = t.replace(/<[^>]+>/g, ' ');
  t = t.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
  t = t.replace(/\[([^\]]+)\]\((?:javascript:[^)]+|https?:\/\/[^)]+)?\)/gi, '$1');
  t = t.replace(/https?:\/\/\S+/g, '');
  t = t.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
  t = t.replace(/[ \t]+/g, ' ');
  t = t.replace(/\n{3,}/g, '\n\n');
  return t.trim();
}

function findTitleStart(text, title) {
  const t = String(text || '');
  const candidates = [];
  const rawTitle = String(title || '').replace(/–.*$/g, '').replace(/\|.*$/g, '').trim();
  if (rawTitle.length >= 8) candidates.push(rawTitle);
  const compact = rawTitle.replace(/["“”'‘’]/g, '').trim();
  if (compact !== rawTitle && compact.length >= 8) candidates.push(compact);
  for (const c of candidates) {
    const idx = t.indexOf(c);
    if (idx >= 0) return Math.max(0, idx - 80);
  }
  return -1;
}

function cutByHints(text, rule, title) {
  let t = String(text || '');

  const titleStart = findTitleStart(t, title);
  if (titleStart >= 0) {
    t = t.slice(titleStart);
  } else if (rule) {
    const startPositions = [];
    for (const hint of (rule.startHints || [])) {
      const idx = t.indexOf(hint);
      if (idx >= 0) startPositions.push(idx);
    }
    if (startPositions.length) {
      const start = Math.max(0, Math.min(...startPositions) - 80);
      t = t.slice(start);
    }
  }

  const stopCandidates = [...((rule && rule.stopHints) || []), ...COMMON_STOP_HINTS];
  let stop = -1;
  for (const hint of stopCandidates) {
    const idx = t.indexOf(hint);
    if (idx > 450 && (stop === -1 || idx < stop)) stop = idx;
  }
  if (stop > 0) t = t.slice(0, stop);
  return t;
}

function removeNoiseLines(text, rule, host = '') {
  const removeIncludes = [...COMMON_REMOVE_INCLUDES, ...((rule && rule.removeIncludes) || [])];
  const lines = String(text || '').split('\n').map(line => line.trim()).filter(Boolean);

  const filtered = lines.filter(line => {
    if (!line) return false;
    if (line.length <= 2) return false;
    if (/^[-*#\s]*$/.test(line)) return false;
    if (/^!?\[?Image\s*\d+/i.test(line)) return false;
    if (/^\*?\s*\[/.test(line) && line.length < 110) return false;
    if (/javascript:/i.test(line)) return false;
    if (/^(홈|뉴스|경제|정치|사회|국제|문화|스포츠|오피니언|전체기사|검색|메뉴|닫기|더보기|LIVE|Powered by)$/i.test(line)) return false;
    if (/^(페이스북|트위터|카카오스토리|네이버블로그|URL복사|메일|프린트)$/.test(line)) return false;
    if (/^[가-힣A-Za-z0-9\s]{1,12}\s*(홈|더보기)$/.test(line)) return false;
    if (removeIncludes.some(w => line.includes(w))) return false;
    if (COMMON_STOP_HINTS.some(w => line === w)) return false;
    if (/^[-*•]/.test(line) && line.length < 70) return false;
    if (/^[#]+\s*(많이 본|관련|추천|시리즈|NEW|PICK|실시간|Y녹취록)/.test(line)) return false;
    if (hostMatches(host, 'mk.co.kr') && /요$|이에요|있어요|예상돼요|보여요|답니다/.test(line) && line.length < 220) return false;
    return true;
  });

  const seen = new Set();
  const deduped = [];
  for (const line of filtered) {
    const key = line.replace(/\s+/g, ' ').slice(0, 140);
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(line);
  }

  return deduped.join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

function scoreArticleQuality(text, title = '', keyword = '') {
  const t = String(text || '');
  const lines = t.split('\n').map(x => x.trim()).filter(Boolean);
  let score = 50;

  if (t.length > 800) score += 8;
  if (t.length > 1800) score += 10;
  if (t.length < 500) score -= 25;
  if (t.length < 250) score -= 35;

  const strongNoise = [
    'YTN star 더보기', '시리즈 더보기', '지금 이뉴스 더보기', '당신이 놓친 기사', '실시간 랭킹',
    '매일경제 AI 검색 이용방법', 'Powered by', 'AI기능', 'Key Points', '사건 개요:',
    '보다 다양한 삼성전자 소식은?', '다운로드', '사이트맵', '대표전화', '사업자등록번호', 'Copyright'
  ];
  const noiseWords = [...COMMON_STOP_HINTS, ...COMMON_REMOVE_INCLUDES, ...strongNoise];
  const noiseCount = noiseWords.reduce((sum, w) => sum + (t.includes(w) ? 1 : 0), 0);
  score -= noiseCount * 7;

  const linkLikeLines = lines.filter(line =>
    line.includes('http') || line.includes('![Image') || /^\*?\s*\[/.test(line) || /^Image\s*\d+/i.test(line) || line.includes('javascript:')
  ).length;
  const linkRatio = lines.length ? linkLikeLines / lines.length : 0;
  if (linkRatio > 0.15) score -= 15;
  if (linkRatio > 0.30) score -= 30;

  const terms = String(title + ' ' + keyword)
    .replace(/["'“”‘’]/g, ' ')
    .split(/[\s,，·|/()\[\]{}:;]+/)
    .map(x => x.trim())
    .filter(x => x.length >= 2)
    .slice(0, 20);
  const hitCount = terms.filter(term => t.includes(term)).length;
  if (hitCount >= 4) score += 12;
  else if (hitCount >= 2) score += 6;
  else if (hitCount === 0) score -= 12;

  const sentenceLikeLines = lines.filter(line =>
    line.length >= 25 && /다\.|다$|했다|밝혔다|전했다|설명했다|계획이다|추진한다|완료했다|강조했다/.test(line)
  ).length;
  if (sentenceLikeLines >= 6) score += 15;
  else if (sentenceLikeLines >= 3) score += 8;
  else if (sentenceLikeLines < 2) score -= 15;

  return Math.max(0, Math.min(100, Math.round(score)));
}

function compressByParagraphs(text, keyword, title, maxChars = 3200) {
  const t = String(text || '').trim();
  if (t.length <= maxChars) return t;

  const paragraphs = t
    .split(/\n{2,}|(?<=다\.)\s+(?=[가-힣A-Z0-9])/g)
    .map(p => p.trim())
    .filter(p => p.length >= 35);

  const queryTerms = String(keyword + ' ' + title)
    .replace(/["'“”‘’]/g, ' ')
    .split(/[\s,，·|/()\[\]{}:;]+/)
    .map(x => x.trim())
    .filter(x => x.length >= 2)
    .slice(0, 25);

  const strategicTerms = ['삼성', '해외', '거점', '생산', '관세', '통상', '인수', 'M&A', '법인', '공장', '서비스', '네트워크', '임직원', '주재원', '현지', '글로벌', 'B2B', 'AI', '데이터센터', '공급망', '확대', '운영'];

  const scored = paragraphs.map((p, idx) => {
    let score = 0;
    if (idx < 5) score += 8;
    if (idx < 10) score += 3;
    for (const term of queryTerms) if (p.includes(term)) score += 5;
    for (const term of strategicTerms) if (p.includes(term)) score += 3;
    if (/밝혔다|말했다|계획|추진|완료|인수|대응|확대|운영|유지|공급|진출/.test(p)) score += 5;
    if (/기자|입력|수정|Copyright|무단|많이 본|Key Points|이에요|있어요|Powered by/.test(p)) score -= 8;
    return { p, score, idx };
  });

  const keepCount = Math.min(14, Math.max(6, Math.ceil(maxChars / 350)));
  const selected = scored
    .sort((a, b) => b.score - a.score || a.idx - b.idx)
    .slice(0, keepCount)
    .sort((a, b) => a.idx - b.idx)
    .map(x => x.p);

  let output = selected.join('\n\n');
  if (output.length > maxChars) output = output.slice(0, maxChars);
  return output.trim();
}

function cleanArticle(item, matched, keyword) {
  const url = getItemUrl(item, matched);
  const host = getHost(url);
  const rule = getDomainRule(host);
  const rawText = String(item.content || item.raw_content || item.text || item.markdown || item.content_text || '');
  const rawChars = rawText.length;
  const title = item.title || matched.title || '';

  let text = stripMarkdownAndHtml(rawText);
  text = cutByHints(text, rule, title);
  text = removeNoiseLines(text, rule, host);

  const compressed = compressByParagraphs(text, keyword, title, 3200);
  const quality = scoreArticleQuality(compressed, title, keyword);

  let warning = '';
  if (quality < 40) warning = '본문 추출 품질이 낮습니다. 원문 확인이 필요합니다.';
  else if (quality < 60) warning = '본문 추출 품질이 중간 이하입니다. 메뉴·푸터 노이즈가 일부 남았을 수 있습니다.';
  else if (compressed.length < 600) warning = '본문 길이가 짧아 기사 핵심이 일부 누락되었을 수 있습니다.';

  return {
    url,
    host,
    raw_chars: rawChars,
    cleaned_chars: compressed.length,
    quality_score: quality,
    cleaning_method: rule ? 'domain_rule' : 'common_rule',
    extraction_warning: warning,
    content: compressed
  };
}


