// AI 응답 파싱 (관대한 복구 로직 - 뉴스레터 파이프라인과 동일한 방식)
let content =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.content ||
  $json.result ||
  '';

function repairJsonText(input) {
  let s = String(input || '')
    .replace(/^\uFEFF/, '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last >= first) s = s.slice(first, last + 1);

  s = s
    .replace(/\bNone\b/g, 'null')
    .replace(/\bTrue\b/g, 'true')
    .replace(/\bFalse\b/g, 'false')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/}\s*{/g, '},{')
    .replace(/]\s*\[/g, '],[')
    .replace(/}\s*"/g, '},"')
    .replace(/]\s*"/g, '],"')
    .replace(/"(\s+)"/g, '",$1"');

  let out = '';
  let inString = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (inString) {
      if (escaped) { out += ch; escaped = false; continue; }
      if (ch === '\\') { out += ch; escaped = true; continue; }
      if (ch === '"') { inString = false; out += ch; continue; }
      if (ch === '\n') { out += '\\n'; continue; }
      if (ch === '\r') continue;
      if (ch === '\t') { out += '\\t'; continue; }
      out += ch;
    } else {
      if (ch === '"') inString = true;
      out += ch;
    }
  }
  return out;
}

function parseJsonRobust(v) {
  if (v && typeof v === 'object') return v;
  const original = String(v || '');
  const repaired = repairJsonText(original);
  try {
    return JSON.parse(repaired);
  } catch (firstError) {
    const secondPass = repaired
      .replace(/}\s*,?\s*(?={)/g, '},')
      .replace(/]\s*,?\s*(?="(?:executive_brief|fact_summary|analysis|recommendations|source_summaries)")/g, '],');
    return JSON.parse(secondPass); // 여기서도 실패하면 그대로 throw
  }
}

let parsed;
let parseFailed = false;
let parseErrorDetail = '';

if (typeof content === 'object' && content !== null) {
  parsed = content;
} else {
  try {
    parsed = parseJsonRobust(content);
  } catch (e) {
    // 복구 로직으로도 파싱이 완전히 실패한 경우.
    // 절대로 "정상적으로 생성된 리포트"처럼 위장하지 않는다 (success는 아래에서 false로 표시됨).
    parseFailed = true;
    parseErrorDetail = e.message || String(e);
    parsed = {
