      source_summaries: [],
      recommended_next_search: [],
      limitations: ''
    };
  }
}

// 안전한 배열/문자열 처리
function asArray(value) {
  if (Array.isArray(value)) return value.filter(v => v !== null && v !== undefined).map(String);
  if (typeof value === 'string' && value.trim()) return [value];
  return [];
}
function asText(value) {
  return value == null ? '' : String(value);
}
function asObj(value, defaults) {
  return (value && typeof value === 'object' && !Array.isArray(value)) ? value : defaults;
}

// 메타 정보
const keyword = asText(parsed.keyword || extractData.keyword || '');
const reportType = asText(parsed.report_type || extractData.report_type || 'trend_brief');
const reportTypeLabel = asText(parsed.report_type_label || extractData.report_type_label || '트렌드 브리프');
const analysisViewpoint = asText(parsed.analysis_viewpoint || extractData.analysis_viewpoint || '');
