    discussion_agenda: asArray(recommendations.discussion_agenda),
    open_questions: asArray(recommendations.open_questions)
  },
  source_summaries: (() => {
    // AI 응답(parsed.source_summaries)을 그대로 믿지 않는다.
    // title/url은 실제 선택된 원본 문서(extractData.documents)에서 100% 신뢰 가능한
    // 값을 직접 가져와 사용하고, summary 등 "분석"이 필요한 필드만 AI 응답에서 채운다.
    // AI가 해당 항목을 비워서 응답하더라도(토큰 소진 등), 최소한 실제 기사 제목과
    // 원문 링크는 항상 보장된다. AI의 summary가 비어 있으면 검색 단계에서 이미
    // 확보한 원문 스니펫(search_summary)으로 대체해 "빈 항목"이 나오지 않게 한다.
    const docs = Array.isArray(extractData.documents) ? extractData.documents : [];
    const aiSummaries = asArray(parsed.source_summaries);

    return docs.map((doc, idx) => {
      const docUrl = String(doc.url || '').trim();
      const ai = aiSummaries.find(s => s && String(s.url || '').trim() === docUrl && docUrl)
        || aiSummaries[idx]
        || {};
      return {
        title: asText(doc.title) || asText(ai.title) || `자료 ${idx + 1}`,
        url: docUrl,
        source_type: asText(ai.source_type || '기타'),
        summary: asText(ai.summary) || asText(doc.search_summary) || '',
        notable_points: asArray(ai.notable_points),
        reliability_note: asText(ai.reliability_note)
      };
    });
  })(),
  recommended_next_search: asArray(parsed.recommended_next_search),
  limitations: asText(parsed.limitations)
};

