// 최종 응답
return {
  success: !parseFailed,
  parse_error: parseFailed ? parseErrorDetail : '',
  raw_ai_response_preview: parseFailed ? String(content).slice(0, 1500) : '',
  keyword,
  report_type: reportType,
  report_type_label: reportTypeLabel,
  analysis_viewpoint: analysisViewpoint,
  analysis_viewpoint_label: analysisViewpointLabel,
  audience_level: audienceLevel,
