// Workflow 2 최종 리포트를 Google Sheets 저장용 1행 데이터로 변환
const result = ($json && typeof $json === 'object' && !Array.isArray($json)) ? $json : {};
const now = new Date();

const datePart = now.toISOString().slice(0, 10).replace(/-/g, '');
const randomPart = Math.random().toString(36).slice(2, 7).toUpperCase();
const researchId = `RES-${datePart}-${randomPart}`;

const raw =
  result.raw && typeof result.raw === 'object' && !Array.isArray(result.raw)
    ? result.raw
    : {};

const executiveBrief =
  raw.executive_brief && typeof raw.executive_brief === 'object'
    ? raw.executive_brief
    : {};

let rawJson = '{}';
try {
  rawJson = JSON.stringify(raw);
} catch (e) {
  rawJson = JSON.stringify({
    serialization_error: true,
    message: e.message || 'raw JSON serialization failed'
  });
}

// AI 응답 파싱이 실패했으면(success !== true) 뉴스레터로는 절대 흘려보내지 않는다.
// 시트에는 감사(audit)를 위해 기록은 남기되, newsletter_candidate를 false로 표시해
// 다운스트림(뉴스레터 파이프라인)에서 자동으로 제외되도록 한다.
const parseOk = result.success === true;

return {
  json: {
    research_id: researchId,
    created_at: result.summarized_at || result.requested_at || now.toISOString(),
    keyword: String(result.keyword || ''),
    report_type: String(result.report_type || ''),
    analysis_viewpoint: String(result.analysis_viewpoint || ''),
    audience_level: String(result.audience_level || ''),
    source_count: Number.isFinite(Number(result.source_count))
      ? Number(result.source_count)
      : 0,
    newsletter_candidate: parseOk,
    newsletter_priority: 50,
    newsletter_reason: parseOk ? '' : `AI 응답 파싱 실패: ${String(result.parse_error || '').slice(0, 200)}`,
    one_line_conclusion: parseOk ? String(executiveBrief.one_line_conclusion || '') : '',
    raw_json: rawJson,
    original_response: {
      ...result,
      research_id: researchId,
      saved_to_research_db: true
    }
  }
};

const saved = $('8-A. Code - Google Sheets 저장 데이터 생성').first().json || {};
const original =
  saved.original_response && typeof saved.original_response === 'object'
    ? saved.original_response
    : {};

const sheetResult = ($json && typeof $json === 'object') ? $json : {};
const sheetError =
  sheetResult.error ||
  sheetResult.message ||
  sheetResult.description ||
  '';

return {
  json: {
    ...original,
    saved_to_research_db: sheetError ? false : true,
    research_db_error: sheetError ? String(sheetError) : ''
  }
};
